      WITH filtered_workouts AS (
        SELECT
          workout_id,
          CAST(COALESCE(started_at, created_at) AS TIMESTAMP) AS workout_time,
          COALESCE(duration_seconds, 0) AS duration_seconds
        FROM hevy.workouts
        %s
      ),
      set_by_workout AS (
