      SELECT
        DATE_TRUNC('%s', fw.workout_time) AS period_start,
        COUNT(*) AS workouts,
        COUNT(DISTINCT CAST(fw.workout_time AS DATE)) AS training_days,
        COALESCE(SUM(fw.duration_seconds), 0) AS duration_seconds,
