      FROM filtered_workouts fw
      LEFT JOIN set_by_workout sw
        ON sw.workout_id = fw.workout_id
      GROUP BY period_start
      ORDER BY period_start %s
      LIMIT %d
      OFFSET %d
      ",
      where_sql,
      grain,
      order,
      limit,
      offset
    ),
    params = params
  )
